function getRandom(x){
  return Math.floor(Math.random()*x);
};

// Base character
function base(race = '人類', myName='尚未取名'){
  this.race = String(race); // race
  this.myName = String(myName); // name
}

// Character stats
function Character(atk = 10, hp = 100, sp = 50, job = '初心者') {
  base.call(this, '人類', 'Ray');
  this.atk = Number(atk); // base attack
  this.hp = Number(hp); // HP
  this.sp = Number(sp); // SP (magic)
  this.job = String(job); // job
}

