function WhiteSmith(job, CartKg) {
  // After a job change your stats definitely change
  Character.call(this, 999, 30000, 900, job); // After a job change, damage, HP, and job all change, so we have to pass them in again
  this.CartKg = CartKg; // cart weight
  this.Status = false; // the cart attack skill needs Cart Boost active before you can attack
}

// The WhiteSmith also inherits the abilities of the starting character
WhiteSmith.prototype = Object.create(Character.prototype);
WhiteSmith.prototype.constructor = WhiteSmith;
// WhiteSmith-only skills

// Cart Boost
WhiteSmith.prototype.CARTBOOST = function() {
  this.Status = true;

  console.log(this.myName + '正在使用手推車加速！');

  // Back to normal after five seconds
  setTimeout(() => {
    this.Status = false;
    console.log('手推車加速狀態結束！');
  }, 5000); 
}

// Cart Termination
WhiteSmith.prototype.CARTTERMINATION = function() {
  if(this.Status) {
    console.log(this.myName + '對怪物照成了' + this.atk * (this.CartKg / 1000) + '固定傷害');
  } else {
    console.error('你還沒有使用手推車加速！');
  }
}


